          ["\\(", "\\)"],
        ],
      },
      svg: {
        fontCache: "global",
      },
    };
  }, []);

  return (
    <>
      <Script
        id="mathjax-script"
        src="https://cdn.jsdelivr.net/npm/mathjax@3/es5/tex-mml-chtml.js"
        strategy="lazyOnload"
      />
      <AISmollmWebGPU />
    </>
  );
}

